  let minVal = Infinity;
  let maxVal = -Infinity;
  let argMax = null;
  for (let n = 2; n <= N_PRIMES; n += 1) {
    const g = (sieveData.primes[n] - sieveData.primes[n - 1]) / Math.log(n);
